// Filter users by email domain: only .net and .org
const items = $input.all().map(item => item.json);

const filtrados = items.filter(user => {
  const email = user.email || '';
  return email.endsWith('.net') || email.endsWith('.org');
});

return filtrados.map(user => ({ json: user }));

const user = $input.item.json;
const now = new Date().toISOString();
const correlationId = $env.CORRELATION_ID ?? crypto.randomUUID();

const payload = {
  source: 'flowgate-automation',
  correlationId: correlationId,
  timestamp: now,
  user: {
    id: user.id,
    name: user.name,
    email: user.email,
    company: user.company ? user.company.name : '',
    city: user.address ? user.address.city : ''
  }
};

return { json: payload };
